<?php
use App\Http\Controllers\Auth\AuthenticatedSessionController; use App\Http\Controllers\Auth\RegisteredUserController; use Illuminate\Support\Facades\Password; use Illuminate\Http\Request; use Illuminate\Support\Facades\Route;
Route::middleware('guest')->group(function(){ Route::get('register',[RegisteredUserController::class,'create'])->name('register'); Route::post('register',[RegisteredUserController::class,'store'])->middleware('throttle:5,1'); Route::get('login',[AuthenticatedSessionController::class,'create'])->name('login'); Route::post('login',[AuthenticatedSessionController::class,'store'])->middleware('throttle:5,1'); Route::get('forgot-password', fn()=>view('auth.forgot-password'))->name('password.request'); Route::post('forgot-password', function(Request $request){ $request->validate(['email'=>'required|email']); Password::sendResetLink($request->only('email')); return back()->with('status','Link reset password dikirim jika email terdaftar.'); })->name('password.email')->middleware('throttle:3,1'); });
Route::post('logout',[AuthenticatedSessionController::class,'destroy'])->middleware('auth')->name('logout');
